const envelope = $json || {};
const body = envelope.body && typeof envelope.body === 'object' ? envelope.body : envelope;
const entries = Array.isArray(body.entry) ? body.entry : [];
const configuredBusinessId = String($env["IG_INSTAGRAM_BUSINESS_ACCOUNT_ID"] || '').trim();

function asText(value) {
  if (typeof value === 'string') return value;
  if (value && typeof value.body === 'string') return value.body;
  if (value && typeof value.text === 'string') return value.text;
  return '';
}

function normalizeCandidate(candidate) {
  const entry = candidate.entry || {};
  const event = candidate.event || {};
  const value = candidate.value || {};
  const message = candidate.message || event.message || {};
  const sender = event.sender || message.from || value.sender || {};
  const recipient = event.recipient || value.recipient || {};
  const entryId = String(entry.id || '').trim();
  const senderId = String(sender.id || sender.user_ref || message.from?.id || '').trim();
  const recipientId = String(recipient.id || value.metadata?.id || entryId || '').trim();
  const businessId = configuredBusinessId || recipientId || entryId;
  const isOutboundEcho = Boolean(configuredBusinessId && senderId === configuredBusinessId);
  const messageId = String(message.mid || message.id || event.message?.mid || event.message?.id || '').trim();
  const messageText = asText(message.text || event.message?.text || message).trim();
  const timestamp = event.timestamp || entry.time || value.timestamp || Date.now();
  const threadId = isOutboundEcho && recipientId ? recipientId : senderId || entryId;

  return {
    tenant_id: $env["DEFAULT_TENANT_ID"] || 'demo',
    channel: 'instagram',
    event_type: 'instagram_message',
    source_object: body.object || 'instagram',
    ig_business_account_id: businessId,
    instagram_sender_id: senderId,
    instagram_recipient_id: recipientId,
    instagram_thread_id: threadId,
    thread_id: threadId,
    instagram_message_id: messageId,
    message_id: messageId,
    message_text: messageText,
    message_type: messageText ? 'text' : 'unknown',
    event_timestamp: timestamp,
    raw_event: body,
    is_outbound_echo: isOutboundEcho,
    is_instagram_message: Boolean(senderId && messageText),
    is_valid_message: Boolean(senderId && messageText),
  };
}

const candidates = [];
for (const entry of entries) {
  if (Array.isArray(entry.messaging)) {
    for (const event of entry.messaging) candidates.push({ entry, event });
  }
  if (Array.isArray(entry.changes)) {
    for (const change of entry.changes) {
      const value = change.value || {};
      const messages = Array.isArray(value.messages) ? value.messages : [];
      for (const message of messages) candidates.push({ entry, value, message });
    }
  }
}

const normalized = candidates.map(normalizeCandidate).find((item) => item.is_valid_message) || {
  tenant_id: $env["DEFAULT_TENANT_ID"] || 'demo',
  channel: 'instagram',
  event_type: 'ignored',
  raw_event: body,
  is_instagram_message: false,
  is_valid_message: false,
};

return { json: normalized };

