const source = $node['Parse Embedding'].json || {};
const inputItems = typeof $input !== 'undefined' ? $input.all() : [];
const rows = inputItems
  .flatMap((item) => {
    const value = item && item.json;
    return Array.isArray(value) ? value : [value];
  })
  .filter((row) => row && typeof row === 'object' && (row.id || row.chunk_text || row.similarity !== undefined));

const threshold = Number(source.min_similarity || source.similarity_threshold || source.rag_min_similarity || 0.22);
const minSimilarity = Math.max(0, Math.min(1, threshold));
const messageText = String(source.message_text || source.text || source.latest_message || '').trim();
const lowerMessage = messageText.toLowerCase();

const docs = rows
  .map((row) => ({
    ...row,
    similarity: Number(row.similarity || 0),
    chunk_text: String(row.chunk_text || row.content || '').trim(),
  }))
  .filter((row) => row.chunk_text.length > 0)
  .sort((a, b) => Number(b.similarity || 0) - Number(a.similarity || 0));

const retrievalSimilarity = docs.reduce((max, row) => Math.max(max, Number(row.similarity || 0)), 0);
const retrievedIds = docs.map((row) => row.id).filter(Boolean);
const retrievedSources = docs.map((row) => row.source_key || row.source_type || row.id).filter(Boolean);
const languages = docs.map((row) => row.language).filter(Boolean);

const salesIntent = /\b(service|services|website|site|web\s*site|landing|shop|store|ecommerce|build|automation|automate|bot|instagram|telegram|crm|lead|sales|price|pricing|cost|quote|proposal|offer|package|consult|audit|funnel|payment|marketplace|content|support)\b/i.test(lowerMessage)
  || /\b(услуг|сайт|лендинг|магазин|автоматизац|бот|цена|стоимост|коммерчес|лид|продаж|воронк|инстаграм|телеграм|crm|срм)\b/i.test(lowerMessage);
const hardHandoff = /\b(human|operator|manager|escalate|complaint|refund|legal|lawyer|angry|urgent|real person|human agent|live agent|support person)\b/i.test(lowerMessage)
  || /\b(человек|оператор|менеджер|жалоб|возврат|юрист|срочно|живой)\b/i.test(lowerMessage);
const hongKongSignal = /\b(hong kong|hk|hkd|hongkong|cantonese|粤|香港|港币|港幣)\b/i.test(lowerMessage);
const chineseSignal = /[\u3400-\u9fff]/.test(messageText);
const preferredCurrency = hongKongSignal || chineseSignal ? 'HKD' : 'USD';

const salesCriticalContext = docs.some((row) => {
  const haystack = [row.source_type, row.source_key, row.language, row.chunk_text].join(' ').toLowerCase();
  return haystack.includes('private_bot_memory')
    || haystack.includes('sales')
    || haystack.includes('pricing')
    || haystack.includes('price')
    || haystack.includes('offer')
    || haystack.includes('service')
    || haystack.includes('playbook')
    || haystack.includes('dialogue')
    || haystack.includes('usd')
    || haystack.includes('hkd')
    || haystack.includes('website')
    || haystack.includes('automation');
});

const answerableNearThreshold = salesIntent && docs.length > 0 && retrievalSimilarity >= Math.max(0.05, minSimilarity - 0.12);
const salesContextOverride = salesIntent && salesCriticalContext;
const salesFallbackAllowed = salesIntent && !hardHandoff;
const salesFallbackUsed = salesFallbackAllowed && (docs.length === 0 || (!salesContextOverride && !answerableNearThreshold && retrievalSimilarity < minSimilarity));

let decisionReason = 'answerable_confidence';
let escalateByConfidence = false;
if (hardHandoff) {
  decisionReason = 'explicit_handoff_request';
  escalateByConfidence = true;
} else if (docs.length === 0 && salesFallbackAllowed) {
  decisionReason = 'sales_discovery_fallback_no_rag_match';
  escalateByConfidence = false;
} else if (docs.length === 0) {
  decisionReason = 'no_retrieved_context';
  escalateByConfidence = true;
} else if (salesContextOverride) {
  decisionReason = 'sales_context_override';
  escalateByConfidence = false;
} else if (answerableNearThreshold) {
  decisionReason = 'near_threshold_with_context';
  escalateByConfidence = false;
} else if (retrievalSimilarity < minSimilarity && salesFallbackAllowed) {
  decisionReason = 'sales_discovery_fallback_low_similarity';
  escalateByConfidence = false;
} else if (retrievalSimilarity < minSimilarity) {
  decisionReason = 'low_rag_confidence';
  escalateByConfidence = true;
}

const retrievedContext = docs
  .map((row, index) => {
    const sourceLabel = row.source_key || row.source_type || row.id || ('source_' + (index + 1));
    const similarity = Number.isFinite(row.similarity) ? row.similarity.toFixed(3) : '0.000';
    return 'Source ' + (index + 1) + ': ' + sourceLabel + ' (similarity ' + similarity + ')\n' + row.chunk_text;
  })
  .join('\n\n---\n\n');

const salesFallbackContext = [
  'Sales discovery fallback for broad inbound commercial questions when Supabase RAG is weak or empty.',
  'Allowed generic offer families: AI automation, Instagram/Telegram bots, lead-response systems, CRM/workflow automation, websites, landing pages, funnels, ecommerce/shop builds, payment flows, content/marketplace operations, and customer-support automations.',
  'For website-build interest: acknowledge the website request, connect it to lead capture, CRM, analytics, payment, and DM automation only when relevant, then ask whether they need a landing page, company website, ecommerce/shop, or full funnel.',
  'Default currency policy: use ' + preferredCurrency + '. Use HKD only when the customer clearly mentions Hong Kong/HK or writes in Cantonese/Chinese; otherwise use USD.',
  'Do not invent exact prices, timelines, case studies, discounts, guarantees, or credentials. If exact retrieved pricing is missing, say pricing depends on scope and ask one specific qualification question.',
  'Escalate only for explicit human handoff requests, legal/refund/complaint/urgent/sensitive account-specific cases, or after repeated failed attempts where the user cannot be helped safely.'
].join('\n');

const retrievalContext = retrievedContext || (salesFallbackUsed ? salesFallbackContext : 'No matching context found in Supabase vector store.');

const promptSystem = [
  'You are Sell.Systems inbound sales assistant for Instagram DMs.',
  'Your job is to turn inbound messages into qualified sales conversations while staying accurate.',
  'Use retrieved company context for factual claims. If fallback sales-discovery context is provided because retrieval is weak or empty, use it only for generic discovery and offer-family framing; do not invent exact prices, dates, promises, credentials, or case studies.',
  'Default to USD for public/international pricing. Use HKD only when the customer clearly indicates Hong Kong/HK, Cantonese/Chinese, or asks for HKD.',
  'For broad service, automation, website, bot, CRM, pricing, or lead-generation questions: keep the conversation moving, explain the likely relevant offer family briefly, and ask one concrete qualification question.',
  'If the user wants a website, ask what type they need: landing page, company website, ecommerce/shop, or a full funnel. Mention automation/lead capture only when useful.',
  'Never escalate only because RAG retrieval is weak for a normal sales question. Escalate only if the user explicitly asks for a human/operator/manager, requests legal/refund/complaint handling, or shares a sensitive account-specific issue that requires a human.',
  'Be concise, natural, and direct. Match the user language when obvious.'
].join('\n');

const promptUser = 'Latest customer message:\n' + (messageText || '(empty)') + '\n\nRetrieved/fallback context:\n' + retrievalContext;

return [{
  json: {
    ...source,
    message_text: messageText,
    retrieval_context: retrievalContext,
    prompt_system: promptSystem,
    prompt_user: promptUser,
    rag_confidence: retrievalSimilarity,
    confidence: retrievalSimilarity,
    similarity_threshold: minSimilarity,
    matched_document_ids: retrievedIds,
    matched_sources: retrievedSources,
    matched_languages: languages,
    sales_intent: salesIntent,
    sales_context_override: salesContextOverride,
    sales_fallback_used: salesFallbackUsed,
    preferred_currency: preferredCurrency,
    escalation_decision_reason: decisionReason,
    escalate_by_confidence: escalateByConfidence,
  }
}];

const source = $json;
const reply = 'I will ask a human operator to review this and follow up. I will stay silent here until the operator resets the handoff marker.';
return [{
  json: {
    ...source,
    llm_answer: reply,
    llm_raw: { escalated: true, reason: source.decision_reason || 'escalation_required' },
    escalated: true,
    answer_confidence: source.retrieval_similarity || 0,
    model_name: 'handoff_rule',
    generated_at: new Date().toISOString()
  }
}];

