const source = $node['Build Retrieval Context'].json || {};
const response = $json || {};
const content = response.choices?.[0]?.message?.content;
const rawAnswer = typeof content === 'string' ? content.trim() : '';
const answer = rawAnswer.length > 0
  ? rawAnswer
  : 'I could not produce a response from the model. A support agent will follow up soon.';
const score = Number(source.retrieval_similarity || 0);
const sourceModel = source.openai_chat_model || source.tenant_settings?.chat_model || source.llm_model;

return [{
  json: {
    ...source,
    llm_answer: answer,
    escalated: false,
    answer_confidence: Number(Math.min(0.99, 0.35 + score * 0.55).toFixed(3)),
    model_name: response.model || sourceModel || 'gpt-4o-mini',
    generated_at: new Date().toISOString()
  }
}];

